/* ── HELPERS ── */
const getAvg = sc => { const v=Object.values(sc).filter(x=>x>0); return v.length===0?0:(v.reduce((a,b)=>a+b,0)/v.length).toFixed(1); };
const getSectionAvg = (sc,s) => { const v=s.categories.map(c=>sc[c.id]||0).filter(x=>x>0); return v.length===0?0:(v.reduce((a,b)=>a+b,0)/v.length).toFixed(1); };
const getScoreColor = a => { if(a===0)return C.grayLight; if(a>=4)return C.teal; if(a>=3)return C.navyMid; if(a>=2)return C.goldDark; return C.rust; };

